import React, { useState, useEffect, useRef } from 'react';
import { motion, AnimatePresence } from 'framer-motion';
import { FiGlobe, FiChevronDown } from 'react-icons/fi';
import styled from 'styled-components';
import { useLocalization } from '../../hooks/useLocalization';

const SwitcherContainer = styled.div`
  position: relative;
  display: inline-block;

  /* Responsive container adjustments */
  @media (max-width: 768px) {
    order: -1; /* Move language switcher before mobile menu button */
    margin-right: 0.5rem;
  }

  @media (max-width: 480px) {
    margin-right: 0.25rem;
  }
`;

const SwitcherButton = styled(motion.button)`
  display: flex;
  align-items: center;
  gap: 0.5rem;
  padding: 0.5rem 0.75rem;
  background: ${props => props.theme.colors.white};
  border: 1px solid ${props => props.theme.colors.border};
  border-radius: ${props => props.theme.borderRadius.md};
  cursor: pointer;
  font-size: ${props => props.theme.fontSizes.sm};
  font-weight: ${props => props.theme.fontWeights.medium};
  color: ${props => props.theme.colors.text};
  transition: all 0.2s ease;
  min-width: 120px;
  justify-content: space-between;

  /* Desktop hover effects */
  @media (min-width: 769px) and (hover: hover) {
    &:hover {
      border-color: ${props => props.theme.colors.primary};
      box-shadow: 0 2px 8px rgba(139, 69, 19, 0.1);
    }
  }

  &:focus {
    outline: none;
    border-color: ${props => props.theme.colors.primary};
    box-shadow: 0 0 0 3px rgba(139, 69, 19, 0.1);
  }

  .flag {
    font-size: 1.2em;
  }

  .chevron {
    transition: transform 0.2s ease;
    transform: ${props => props.$isOpen ? 'rotate(180deg)' : 'rotate(0deg)'};
  }
`;

const HorizontalDropdownMenu = styled(motion.div)`
  position: absolute;
  top: 100%;
  left: 50%;
  transform: translateX(-50%);
  margin-top: 0.5rem;
  background: ${props => props.theme.colors.white};
  border: 1px solid ${props => props.theme.colors.border};
  border-radius: ${props => props.theme.borderRadius.lg};
  box-shadow: ${props => props.theme.shadows.xl};
  z-index: 1000;
  overflow: hidden;
  display: flex;
  flex-direction: row;
  min-width: auto;
  width: auto;

  /* Mobile adjustments */
  @media (max-width: 768px) {
    box-shadow: 0 6px 25px rgba(0, 0, 0, 0.15);
    backdrop-filter: blur(10px);
    background: rgba(255, 255, 255, 0.95);
    border-radius: ${props => props.theme.borderRadius.xl};
  }

  @media (max-width: 480px) {
    margin-top: 0.4rem;
  }

  @media (max-width: 360px) {
    margin-top: 0.3rem;
  }
`;

const VerticalDropdownMenu = styled(motion.div)`
  position: absolute;
  top: 100%;
  left: 0;
  right: 0;
  margin-top: 0.25rem;
  background: ${props => props.theme.colors.white};
  border: 1px solid ${props => props.theme.colors.border};
  border-radius: ${props => props.theme.borderRadius.md};
  box-shadow: ${props => props.theme.shadows.lg};
  z-index: 1000;
  overflow: hidden;
  min-width: 150px;

  /* Mobile adjustments */
  @media (max-width: 768px) {
    right: 0;
    left: auto;
    min-width: 140px;
    margin-top: 0.5rem;
    box-shadow: 0 4px 20px rgba(0, 0, 0, 0.15);
    backdrop-filter: blur(8px);
    background: rgba(255, 255, 255, 0.95);
  }
`;

const HorizontalLanguageOption = styled(motion.button)`
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 0.25rem;
  padding: 0.75rem 0.5rem;
  background: none;
  border: none;
  border-right: 1px solid ${props => props.theme.colors.border};
  cursor: pointer;
  font-size: ${props => props.theme.fontSizes.xs};
  color: ${props => props.theme.colors.text};
  transition: all 0.2s ease;
  min-height: 60px;
  min-width: 50px;
  text-align: center;

  &:last-child {
    border-right: none;
  }

  /* Desktop hover effects */
  @media (min-width: 769px) and (hover: hover) {
    &:hover {
      background-color: ${props => props.theme.colors.backgroundAlt};
    }
  }

  &.active {
    background-color: rgba(139, 69, 19, 0.1);
    color: ${props => props.theme.colors.primary};
